#include <stdio.h>
#include <stdint.h>
int64_t sum(int64_t n, int64_t m) {
    int64_t sum = 0;
    for (int64_t i = 1; i <= n; i++) {
        sum = (sum + i * i) % m;
    }
    return sum;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int64_t n, m;
        scanf("%lld %lld", &n, &m);
        printf("%lld\n", sum(n, m));
    }
    return 0;
}

