code.Java:
import java.util.Scanner;
public class Main {
    public static long sum(long n, long m) {
        long sum = 0;
        for (long i = 1; i <= n; i++) {
            sum = (sum + i * i) % m;
        }
        return sum;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            long n = sc.nextLong();
            long m = sc.nextLong();
            System.out.println(sum(n, m));
        }
    }
}

